item_ids = input().split()
n = int(input())

item_count = {}

for item in item_ids:
    if item in item_count:
        item_count[item] += 1
    else:
        item_count[item] = 1

result = []
for item, count in item_count.items():
    if count == n:
        result.append(int(item))
result.sort()

result_strings = []
for num in result:
    result_strings.append(str(num))

print(" ".join(result_strings))
